                ["P2-DIRTY-GRAVE-P1-OWNED"] = new(
                    "P2-DIRTY-GRAVE-P1-OWNED",
                    cardNo: "SFD·126/221",
                    tags: [CardObjectTags.UnitCard],
                    ownerId: "P1"),
                ["P2-RUNE-001"] = new(
                    "P2-RUNE-001",
                    cardNo: "RUN·001",
                    tags: [CardObjectTags.RuneCard],
                    ownerId: "P2",
                    controllerId: "P2"),
                ["P2-RUNE-002"] = new(
                    "P2-RUNE-002",
                    cardNo: "RUN·002",
                    tags: [CardObjectTags.RuneCard],
                    ownerId: "P2",
                    controllerId: "P2")
            });

        var result = await new CoreRuleEngine().ResolveAsync(
