        Assert.Equal(2, p2Pass.State.CardObjects["P1-UNIT-CHARMING-SPIRIT"].Power);
        Assert.Equal([CardObjectTags.UnitCard, "灵体"], p2Pass.State.CardObjects["P1-UNIT-CHARMING-SPIRIT"].Tags);
    }

