        Assert.Equal(["P1-SAD-PORO-DRAW"], p2Pass.State.PlayerZones["P1"].Hand);
        Assert.Equal([sourceObjectId, "P1-SPELL-VENGEANCE"], p2Pass.State.PlayerZones["P1"].Graveyard);
    }

