                    "P1-MECHANICAL-TRICKSTER",
                    cardNo: "OGN·239/298",
                    power: 4,
                    tags: [CardObjectTags.UnitCard],
                    ownerId: "P1",
                    controllerId: "P1")
            }
        };

        var play = await engine.ResolveAsync(
