            string.Equals(gameEvent.Kind, "POWER_MODIFIED_UNTIL_END_OF_TURN", StringComparison.Ordinal));
        Assert.Equal(1, powerEvent.Payload["appliedPowerDelta"]);
        Assert.Equal(3, powerEvent.Payload["resultingPower"]);
    }

