                    "P1-UNIT-ASSEMBLE-TARGET",
                    cardNo: "SFD·125/221",
                    power: 3,
                    tags: [CardObjectTags.UnitCard])
            },
            StackItems =
            [
                new StackItemState(
                    "STACK-0-P2-SPELL-PROBE",
