                    cardNo: "UNL-059/219",
                    power: 2,
                    tags: [CardObjectTags.UnitCard, "狩猎2"],
                    ownerId: "P1",
                    controllerId: "P1"),
                ["P2-BATTLEFIELD-DEFENDER"] = new(
                    "P2-BATTLEFIELD-DEFENDER",
                    cardNo: "UNL-036/219",
                    power: 1,
                    tags: [CardObjectTags.UnitCard],
                    ownerId: "P2",
                    controllerId: "P2")
            }
        };

        var result = await new CoreRuleEngine().ResolveAsync(
